CREATE TABLE "accountant_document_notes" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "office_id" UUID NOT NULL, "company_id" UUID NOT NULL, "fiscal_document_id" UUID NOT NULL, "author_user_id" UUID NOT NULL, "content" TEXT NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "deleted_at" TIMESTAMP(3), CONSTRAINT "accountant_document_notes_pkey" PRIMARY KEY ("id"));
CREATE TABLE "accountant_document_tags" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "office_id" UUID NOT NULL, "name" VARCHAR(80) NOT NULL, "normalized_name" VARCHAR(80) NOT NULL, "color" VARCHAR(20), "created_by_user_id" UUID NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "accountant_document_tags_pkey" PRIMARY KEY ("id"));
CREATE TABLE "accountant_document_tag_links" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "office_id" UUID NOT NULL, "company_id" UUID NOT NULL, "fiscal_document_id" UUID NOT NULL, "tag_id" UUID NOT NULL, "assigned_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "accountant_document_tag_links_pkey" PRIMARY KEY ("id"));
CREATE TABLE "accountant_document_requests" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "office_id" UUID NOT NULL, "company_id" UUID NOT NULL, "fiscal_document_id" UUID NOT NULL, "user_id" UUID NOT NULL, "type" VARCHAR(60) NOT NULL, "priority" VARCHAR(20) NOT NULL DEFAULT 'NORMAL', "status" VARCHAR(20) NOT NULL DEFAULT 'OPEN', "description" TEXT, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "accountant_document_requests_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "accountant_document_tags_office_id_normalized_name_key" ON "accountant_document_tags"("office_id", "normalized_name");
CREATE UNIQUE INDEX "accountant_document_tag_links_office_id_fiscal_document_id_tag_id_key" ON "accountant_document_tag_links"("office_id", "fiscal_document_id", "tag_id");
CREATE INDEX "accountant_document_notes_scope_idx" ON "accountant_document_notes"("office_id", "company_id", "fiscal_document_id", "created_at" DESC);
CREATE INDEX "accountant_document_tag_links_scope_idx" ON "accountant_document_tag_links"("office_id", "company_id", "fiscal_document_id");
CREATE INDEX "accountant_document_requests_scope_idx" ON "accountant_document_requests"("office_id", "company_id", "fiscal_document_id", "status");
